#pragma once

// Escape sequences
#define ANSI_CSI            "\x1B["

// Control Sequences
#define ANSI_CURSOR_UP              ANSI_CSI "1A"
#define ANSI_CURSOR_DOWN            ANSI_CSI "1B"
#define ANSI_CURSOR_RIGHT           ANSI_CSI "1C"
#define ANSI_CURSOR_LEFT            ANSI_CSI "1D"

// Select Graphics Rendition
